const body = $input.first().json.body;

// Required field validation
const required = ['lead_name', 'email', 'agent_name', 'agent_email', 'property_address'];
for (const field of required) {
  if (!body[field] || !String(body[field]).trim()) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Email format check
const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRe.test(body.email)) throw new Error('Invalid lead email format');
if (!emailRe.test(body.agent_email)) throw new Error('Invalid agent email format');

// Length caps — prevent oversized payloads to Claude
const maxLengths = { lead_name: 100, lead_message: 2000, property_address: 200, key_details: 1000 };
for (const [field, max] of Object.entries(maxLengths)) {
  if (body[field] && String(body[field]).length > max) {
    throw new Error(`Field too long: ${field} (max ${max} chars)`);
  }
}

return [$input.first()];

