const response = $input.first().json;
const message = response.content[0].text.trim();
const prev = $('Build Prompt').first().json;

const unsub = '<p style="font-size:12px;color:#9EA3AA;border-top:1px solid #E5E4DE;padding-top:16px;margin-top:24px;">To stop receiving these emails, <a href="https://tools.norrai.co/unsubscribe?email=' + encodeURIComponent(prev.lead_email) + '" style="color:#9EA3AA;">click here</a>.</p>';
const email_html = '<p style="font-family:Inter,sans-serif;color:#3A3F48;line-height:1.6;">' + message.replace(/\n/g, '<br>') + '</p>' + unsub;

return [{
  json: {
    message,
    email_html,
    lead_name:        prev.lead_name,
    lead_phone:       prev.lead_phone,
    lead_email:       prev.lead_email,
    agent_name:       prev.agent_name,
    agent_email:      prev.agent_email,
    property_address: prev.property_address
  }
}];

